import os
from langchain_community.document_loaders import DirectoryLoader, TextLoader
from langchain.text_splitter import RecursiveCharacterTextSplitter
from langchain_community.embeddings import HuggingFaceEmbeddings
from langchain_community.vectorstores import FAISS
from langchain.prompts import ChatPromptTemplate
from langchain.schema.runnable import RunnablePassthrough
from langchain.schema.output_parser import StrOutputParser

# --- Configuration ---
DOCS_DIR = "company_docs"
VECTOR_DB_PATH = "faiss_index"
EMBEDDING_MODEL_NAME = "sentence-transformers/all-MiniLM-L6-v2"

# --- 1. Prepare Documents (Create dummy files if they don't exist) ---
if not os.path.exists(DOCS_DIR):
    os.makedirs(DOCS_DIR)
    with open(os.path.join(DOCS_DIR, "hr_policy.txt"), "w") as f:
        f.write("Our company's HR policy states that employees are entitled to 20 days of paid vacation per year after their first year of service. All leave requests must be submitted through the internal portal at least two weeks in advance. Sick leave requires a doctor's note for absences longer than 3 days. Remote work is allowed two days a week with manager approval. We offer competitive salaries and a comprehensive benefits package including health, dental, and vision insurance.")
    with open(os.path.join(DOCS_DIR, "it_security.txt"), "w") as f:
        f.write("IT Security Policy: All company devices must have up-to-date antivirus software. Passwords must be at least 12 characters long, include a mix of uppercase, lowercase, numbers, and special characters, and be changed every 90 days. Phishing emails should be reported immediately to security@company.com. Do not share your login credentials with anyone. Public Wi-Fi should be avoided for sensitive company work.")
    with open(os.path.join(DOCS_DIR, "expense_policy.txt"), "w") as f:
        f.write("Expense Reimbursement Policy: Employees can claim reimbursement for business travel, meals with clients, and necessary work-related purchases. All expenses must be submitted with original receipts within 30 days of incurring the expense. The maximum meal allowance for individual dinners is $50. Travel must be pre-approved by a department head. Personal expenses are not reimbursable.")
    with open(os.path.join(DOCS_DIR, "onboarding_guide.txt"), "w") as f:
        f.write("Welcome to our company! Your onboarding process will involve a meeting with HR, IT setup, and an introduction to your team. Please complete all mandatory training modules within your first two weeks. Your manager will provide a detailed work plan. We encourage new hires to ask questions and explore our internal knowledge base. You'll receive your employee ID and access card on your first day.")

print("Dummy documents created/ensured.")

# --- 2. Load Documents ---
print(f"Loading documents from {DOCS_DIR}...")
loader = DirectoryLoader(DOCS_DIR, glob="*.txt", loader_cls=TextLoader)
documents = loader.load()
print(f"Loaded {len(documents)} documents.")

# --- 3. Split Documents ---
print("Splitting documents into chunks...")
text_splitter = RecursiveCharacterTextSplitter(
    chunk_size=500,
    chunk_overlap=50,
    length_function=len,
    add_start_index=True,
)
chunks = text_splitter.split_documents(documents)
print(f"Split into {len(chunks)} chunks.")

# --- 4. Initialize Embeddings ---
print(f"Initializing embedding model: {EMBEDDING_MODEL_NAME}...")
embeddings = HuggingFaceEmbeddings(model_name=EMBEDDING_MODEL_NAME)

# --- 5. Create or Load Vector Database ---
if os.path.exists(VECTOR_DB_PATH):
    print(f"Loading existing FAISS index from {VECTOR_DB_PATH}...")
    vectorstore = FAISS.load_local(VECTOR_DB_PATH, embeddings, allow_dangerous_deserialization=True)
else:
    print("Creating new FAISS index...")
    vectorstore = FAISS.from_documents(chunks, embeddings)
    vectorstore.save_local(VECTOR_DB_PATH)
    print(f"FAISS index created and saved to {VECTOR_DB_PATH}.")

# --- 6. Set up Retriever ---
retriever = vectorstore.as_retriever(search_kwargs={"k": 5}) # Retrieve top 5 relevant documents

# --- 7. Define LLM (Mock for demonstration) ---
# In a real system, you would integrate with an actual LLM service
# e.g., OpenAI, Anthropic, HuggingFace Inference API, Llama.cpp, etc.
# from langchain_openai import ChatOpenAI
# llm = ChatOpenAI(model_name="gpt-3.5-turbo", temperature=0)

class MockLLM:
    def invoke(self, prompt_value):
        prompt_text = prompt_value.to_string()
        print("\n--- Mock LLM Received Prompt ---")
        print(prompt_text)
        print("---------------------------------")
        return "This is a mock response based on your query and the provided context. (Please replace with a real LLM for actual answers)."

llm = MockLLM()

# --- 8. Define Prompt Template ---
template = """You are an internal knowledge base assistant for our company.
Use the following retrieved context to answer the user's question.
If you don't know the answer, state that you don't have enough information.
Keep your answer concise and helpful.

Retrieved Context:
{context}

User Question: {question}

Your Answer:
"""
prompt = ChatPromptTemplate.from_template(template)

# --- 9. Build the RAG Chain ---
def format_docs(docs):
    """Formats retrieved documents into a single string for the prompt."""
    return "\n\n".join(doc.page_content for doc in docs)

rag_chain = (
    {"context": retriever | format_docs, "question": RunnablePassthrough()}
    | prompt
    | llm
    | StrOutputParser()
)

# --- 10. User Interaction Loop ---
print("\n--- RAG Chatbot Ready ---")
print("Enter your queries. Type 'exit' to quit.")

while True:
    query = input("\nYour Query: ")
    if query.lower() == 'exit':
        break

    print("Searching for relevant information...")
    response = rag_chain.invoke(query)
    print(f"\nBot: {response}")

print("\nThank you for using the RAG chatbot!")